<div class="row"><div class="col-md-8"><div class="form-group"><label>Título</label><input type="text" class="form-control" name="titulo" id="edit_titulo" required></div></div><div class="col-md-4"><div class="form-group"><label>Tipo</label><select class="form-control" name="tipo" id="edit_tipo"><option value="VISITA_TECNICA">Visita Técnica</option><option value="REUNIAO">Reunião</option><option value="MANUTENCAO">Manutenção</option></select></div></div></div>
