<script>
$(document).ready(function() {
    if (!$.fn.DataTable.isDataTable('#tbl_agenda')) $('#tbl_agenda').DataTable({ "info": true, "searching": true, "paging": true, "pageLength": 15, "order": [[4, 'desc']], "language": { "url": "//cdn.datatables.net/plug-ins/9dcbecd42ad/i18n/Portuguese.json" } });
    $('.btn-edit').on('click', function() {
        var id = $(this).data('id');
        $.getJSON('<?= base_url(); ?>agenda/get/' + id, function(data) {
            $('#edit_id').val(data.idevento); $('#edit_titulo').val(data.titulo); $('#edit_tipo').val(data.tipo);
            if (data.data_inicio) $('#edit_data_inicio').val(data.data_inicio.replace(' ', 'T'));
            if (data.data_fim) $('#edit_data_fim').val(data.data_fim.replace(' ', 'T'));
            $('#edit_status').val(data.status); $('#edit_admin_id').val(data.admin_id); $('#edit_cliente_id').val(data.cliente_id);
            $('#edit_local').val(data.local); $('#edit_cor').val(data.cor); $('#edit_descricao').val(data.descricao);
            $('#modalEdit').modal('show');
        });
    });
});
</script>
